#include <bits/stdc++.h>
using namespace std;

const int N=1e3+10,M=3e4+10,INF=1e9;

int n,m,s,t;
int head[N],ver[M],edge[M],nxt[M],tot=1,da[N],db[N];
int S,T,d[N],now[N],q[N];

void add(int x,int y,int z){
    ver[++tot]=y,edge[tot]=z,nxt[tot]=head[x],head[x]=tot;
    ver[++tot]=x,edge[tot]=0,nxt[tot]=head[y],head[y]=tot;
}

bool bfs(){
    memset(d,0,sizeof(d));
    int hh=1,tt=0;
    d[S]=1,now[S]=head[S];
    q[++tt]=S;
    while(hh<=tt){
        int x=q[hh++];
        for(int i=head[x],y;i;i=nxt[i])
            if(edge[i] && !d[y=ver[i]]){
                d[y]=d[x]+1,now[y]=head[y];
                if(y==T) return true;
                q[++tt]=y;
            }
    }
    return false;
}

int Dinic(int x,int flow){
    if(x==T) return flow;
    int res=0;
    for(int i=now[x],y;i && res<flow;i=nxt[i]){
        now[x]=i,y=ver[i];
        if(edge[i] && d[y]==d[x]+1){
            int tmp=Dinic(y,min(edge[i],flow-res));
            if(!tmp) d[y]=0;
            edge[i]-=tmp,edge[i^1]+=tmp;
            res+=tmp;
        }
    }
    return res;
}

int main(){
    scanf("%d%d%d%d",&n,&m,&s,&t);
    for(int i=1;i<=m;i++){
        int u,v,l,r;
        scanf("%d%d%d%d",&u,&v,&l,&r);
        add(u,v,r-l);
        db[u]+=l,da[v]+=l;
    }
    add(t,s,INF);
    S=n+1,T=n+2;
    int sum=0;
    for(int i=1;i<=n;i++){
        if(da[i]>db[i]){
            add(S,i,da[i]-db[i]);
            sum+=da[i]-db[i];
        }
        if(da[i]<db[i])
            add(i,T,db[i]-da[i]);
    }
    int flow,res=0;
    while(bfs())
        while(flow=Dinic(S,INF)) res+=flow;
    if(res<sum){
        puts("N");
        return 0;
    }
    S=s,T=t;
    for(int i=2*m+4;i<=tot;i++) edge[i]=0;
    res=0;
    while(bfs())
        while(flow=Dinic(S,INF)) res+=flow;
    printf("%d",res);
    return 0;
}
